{"items":[{"name":"CategoryTheory.Limits.Types.pi_map_π_apply","module_name":"Mathlib.CategoryTheory.Limits.Types.Products","kind":"theorem","type":"∀ {β : Type v} [inst : Small.{u, v} β] {f g : β → Type u} (α : (j : β) → f j ⟶ g j) (b : β) (x : ∏ᶜ f),
  CategoryTheory.Limits.Pi.π g b (CategoryTheory.Limits.Pi.map α x) = α b (CategoryTheory.Limits.Pi.π f b x)"},{"name":"ModuleCat.binaryProductLimitCone_cone_π_app_left","module_name":"Mathlib.Algebra.Category.ModuleCat.Biproducts","kind":"theorem","type":"∀ {R : Type u} [inst : Ring R] (M N : ModuleCat R),
  (M.binaryProductLimitCone N).cone.π.app { as := CategoryTheory.Limits.WalkingPair.left } =
    ModuleCat.ofHom (LinearMap.fst R ↑M ↑N)"},{"name":"CategoryTheory.NatIso.pi'_hom","module_name":"Mathlib.CategoryTheory.Pi.Basic","kind":"theorem","type":"∀ {I : Type w₀} {C : I → Type u₁} [inst : (i : I) → CategoryTheory.Category.{v₁, u₁} (C i)] {E : Type u_1}
  [inst_1 : CategoryTheory.Category.{v_1, u_1} E] {F G : CategoryTheory.Functor E ((i : I) → C i)}
  (e : (i : I) → F.comp (CategoryTheory.Pi.eval C i) ≅ G.comp (CategoryTheory.Pi.eval C i)),
  (CategoryTheory.NatIso.pi' e).hom = CategoryTheory.NatTrans.pi' fun i => (e i).hom"},{"name":"CategoryTheory.Pi.isoApp_hom","module_name":"Mathlib.CategoryTheory.Pi.Basic","kind":"theorem","type":"∀ {I : Type w₀} {C : I → Type u₁} [inst : (i : I) → CategoryTheory.Category.{v₁, u₁} (C i)] {X Y : (i : I) → C i}
  (f : X ≅ Y) (i : I), (CategoryTheory.Pi.isoApp f i).hom = f.hom i"},{"name":"CategoryTheory.Pi.isoMk_hom","module_name":"Mathlib.CategoryTheory.Pi.Basic","kind":"theorem","type":"∀ {I : Type w₀} {C : I → Type u₁} [inst : (i : I) → CategoryTheory.Category.{v₁, u₁} (C i)] {X Y : (i : I) → C i}
  (iso : (i : I) → X i ≅ Y i) (i : I), (CategoryTheory.Pi.isoMk iso).hom i = (iso i).hom"}]}
